"use client"

import Link from "next/link"
import { Eye, Plus, AlertTriangle, Zap, FileCheck } from "lucide-react"
import type { Actividad } from "@/lib/types"

interface ActivitiesTableProps {
  actividades: Actividad[]
  aportesMap: Record<string, number>
  evidenciasMap: Record<string, number>
  page: number
  pageSize: number
  total: number
  onPageChange: (page: number) => void
}

function getEstado(cobertura: number): {
  label: string
  className: string
} {
  if (cobertura >= 60)
    return {
      label: "ACTIVA",
      className: "bg-emerald-50 text-emerald-700 border border-emerald-200",
    }
  if (cobertura >= 25)
    return {
      label: "BAJA",
      className: "bg-amber-50 text-amber-700 border border-amber-200",
    }
  return {
    label: "SIN INICIO",
    className: "bg-rose-50 text-rose-700 border border-rose-200",
  }
}

function getAlerta(
  cobertura: number
): { icon: typeof AlertTriangle; text: string; className: string } | null {
  if (cobertura > 0 && cobertura < 25)
    return {
      icon: AlertTriangle,
      text: "Baja gestion detectada",
      className: "text-amber-600",
    }
  if (cobertura === 0)
    return {
      icon: Zap,
      text: "IA sugiere accion inmediata",
      className: "text-rose-500",
    }
  return null
}

function getCoberturaColor(cobertura: number): string {
  if (cobertura >= 70) return "#10b981"
  if (cobertura >= 40) return "#3b82f6"
  if (cobertura >= 20) return "#f59e0b"
  return "#ef4444"
}

export function ActivitiesTable({
  actividades,
  aportesMap,
  evidenciasMap,
  page,
  pageSize,
  total,
  onPageChange,
}: ActivitiesTableProps) {
  const totalPages = Math.ceil(total / pageSize)

  return (
    <div className="flex flex-col gap-4">
      <div className="hidden overflow-hidden rounded-lg border border-border md:block">
        <table className="w-full">
          <thead>
            <tr className="bg-sidebar text-sidebar-foreground">
              <th className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                #
              </th>
              <th className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Actividad Contractual
              </th>
              <th className="px-4 py-3 text-center text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Aportes
              </th>
              <th className="px-4 py-3 text-center text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Evidencias
              </th>
              <th className="px-4 py-3 text-center text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Cobertura
              </th>
              <th className="px-4 py-3 text-center text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Estado
              </th>
              <th className="px-4 py-3 text-center text-xs font-semibold uppercase tracking-wider text-sidebar-primary">
                Acciones
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border bg-card">
            {actividades.map((act) => {
              const aportesCount = aportesMap[act.id] ?? 0
              const evidenciasCount = evidenciasMap[act.id] ?? 0
              const maxAportes = Math.max(
                ...Object.values(aportesMap).map(Number),
                1
              )
              const cobertura = Math.round(
                (aportesCount / Math.max(maxAportes, 1)) * 100
              )
              const estado = getEstado(cobertura)
              const alerta = getAlerta(cobertura)

              return (
                <tr
                  key={act.id}
                  className="transition-colors hover:bg-accent/30"
                >
                  <td className="px-4 py-4 text-sm font-medium text-muted-foreground">
                    {String(act.numero).padStart(2, "0")}
                  </td>
                  <td className="max-w-md px-4 py-4">
                    <div className="flex flex-col gap-0.5">
                      <span className="text-sm font-medium text-card-foreground leading-snug">
                        {act.titulo}
                      </span>
                      {alerta ? (
                        <span
                          className={`flex items-center gap-1 text-xs ${alerta.className}`}
                        >
                          <alerta.icon className="h-3 w-3" />
                          {alerta.text}
                        </span>
                      ) : (
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <FileCheck className="h-3 w-3" />
                          Extraida automaticamente del PDF
                        </span>
                      )}
                    </div>
                  </td>
                  <td className="px-4 py-4 text-center text-sm font-medium text-card-foreground">
                    {aportesCount}
                  </td>
                  <td className="px-4 py-4 text-center text-sm font-medium text-card-foreground">
                    {evidenciasCount}
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex items-center justify-center gap-2">
                      <div className="h-2 w-20 overflow-hidden rounded-full bg-muted">
                        <div
                          className="h-full rounded-full transition-all"
                          style={{
                            width: `${cobertura}%`,
                            backgroundColor: getCoberturaColor(cobertura),
                          }}
                        />
                      </div>
                      <span className="text-xs font-medium text-muted-foreground">
                        {cobertura}%
                      </span>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-center">
                    <span
                      className={`inline-block rounded-full px-3 py-1 text-xs font-semibold ${estado.className}`}
                    >
                      {estado.label}
                    </span>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex items-center justify-center gap-1">
                      <Link
                        href={`/actividades/${act.id}`}
                        className="flex h-8 w-8 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-foreground"
                        aria-label={`Ver actividad ${act.numero}`}
                      >
                        <Eye className="h-4 w-4" />
                      </Link>
                      <Link
                        href={`/actividades/nuevo-aporte?actividad=${act.id}`}
                        className="flex h-8 w-8 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-primary/10 hover:text-primary"
                        aria-label={`Agregar aporte a actividad ${act.numero}`}
                      >
                        <Plus className="h-4 w-4" />
                      </Link>
                    </div>
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>

      <div className="flex flex-col gap-3 md:hidden">
        {actividades.map((act) => {
          const aportesCount = aportesMap[act.id] ?? 0
          const evidenciasCount = evidenciasMap[act.id] ?? 0
          const maxAportes = Math.max(
            ...Object.values(aportesMap).map(Number),
            1
          )
          const cobertura = Math.round(
            (aportesCount / Math.max(maxAportes, 1)) * 100
          )
          const estado = getEstado(cobertura)

          return (
            <div
              key={act.id}
              className="flex flex-col gap-3 rounded-lg border border-border bg-card p-4"
            >
              <div className="flex items-start justify-between gap-3">
                <div className="flex items-center gap-2">
                  <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-sidebar text-xs font-bold text-sidebar-primary">
                    {String(act.numero).padStart(2, "0")}
                  </span>
                  <span
                    className={`rounded-full px-2 py-0.5 text-[10px] font-semibold ${estado.className}`}
                  >
                    {estado.label}
                  </span>
                </div>
                <div className="flex items-center gap-1">
                  <Link
                    href={`/actividades/${act.id}`}
                    className="flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-foreground"
                    aria-label={`Ver actividad ${act.numero}`}
                  >
                    <Eye className="h-3.5 w-3.5" />
                  </Link>
                  <Link
                    href={`/actividades/nuevo-aporte?actividad=${act.id}`}
                    className="flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground hover:bg-primary/10 hover:text-primary"
                    aria-label={`Agregar aporte a actividad ${act.numero}`}
                  >
                    <Plus className="h-3.5 w-3.5" />
                  </Link>
                </div>
              </div>
              <p className="text-sm font-medium text-card-foreground leading-snug">
                {act.titulo}
              </p>
              <div className="flex items-center gap-4 text-xs text-muted-foreground">
                <span>{aportesCount} aportes</span>
                <span>{evidenciasCount} evidencias</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="h-1.5 flex-1 overflow-hidden rounded-full bg-muted">
                  <div
                    className="h-full rounded-full"
                    style={{
                      width: `${cobertura}%`,
                      backgroundColor: getCoberturaColor(cobertura),
                    }}
                  />
                </div>
                <span className="text-xs font-medium text-muted-foreground">
                  {cobertura}%
                </span>
              </div>
            </div>
          )
        })}
      </div>

      <div className="flex items-center justify-between">
        <p className="text-sm text-primary">
          Mostrando {actividades.length} de {total} actividades
        </p>
        {totalPages > 1 && (
          <div className="flex items-center gap-1">
            <button
              onClick={() => onPageChange(page - 1)}
              disabled={page <= 1}
              className="flex h-8 w-8 items-center justify-center rounded-md border border-border text-sm text-muted-foreground transition-colors hover:bg-accent disabled:opacity-40 disabled:hover:bg-transparent"
              aria-label="Pagina anterior"
            >
              {"<"}
            </button>
            {Array.from({ length: totalPages }, (_, i) => i + 1).map((p) => (
              <button
                key={p}
                onClick={() => onPageChange(p)}
                className={`flex h-8 w-8 items-center justify-center rounded-md text-sm font-medium transition-colors ${
                  p === page
                    ? "bg-primary text-primary-foreground"
                    : "border border-border text-muted-foreground hover:bg-accent"
                }`}
              >
                {p}
              </button>
            ))}
            <button
              onClick={() => onPageChange(page + 1)}
              disabled={page >= totalPages}
              className="flex h-8 w-8 items-center justify-center rounded-md border border-border text-sm text-muted-foreground transition-colors hover:bg-accent disabled:opacity-40 disabled:hover:bg-transparent"
              aria-label="Pagina siguiente"
            >
              {">"}
            </button>
          </div>
        )}
      </div>
    </div>
  )
}
